def init_state(
    problem: ProblemSpec,
    x0: np.ndarray,
    hyperparameters: dict[str, Any],
) -> dict[str, Any]:
    return {
        "x": as_vector(x0, problem.dim),
        "x_prev": as_vector(x0, problem.dim),
        "k": 0,
    }

def step(
    state: dict[str, Any],
    oracle: Oracle,
    problem: ProblemSpec,
    hyperparameters: dict[str, Any],
) -> StepOutput:
    alpha = float(hyperparameters["alpha"])
    x = as_vector(state["x"], problem.dim)
    k = int(state.get("k", 0))

    g = oracle.grad(x)
    x_next = x - alpha * g

    new_state = {
        "x": x_next,
        "x_prev": x,
        "k": k + 1,
    }
    return StepOutput(state=new_state, x=x_next, num_grad_evals=1)

def get_hyperparameters(
    problem_name: str,
    L: float,
    mu: float,
    dim: int,
) -> dict[str, Any]:
    alpha = 2.0 / (L + mu)
    return {"alpha": alpha, "L": L, "mu": mu}
